"crm.formula.desc50": "\u0432\u043e\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u0435",
"crm.formula.desc45": "\u0433\u043e\u0434, \u043c\u0435\u0441\u044f\u0446, \u0434\u0435\u043d\u044c, \u0433\u043e\u0434, \u043c\u0438\u043d\u0443\u0442\u0430, \u0434\u043e \u043f\u043e\u043b\u0443\u0434\u043d\u044f/\u043f\u043e\u0441\u043b\u0435 \u043f\u043e\u043b\u0443\u0434\u043d\u044f",
